# pip install pytest-mock
import pytest

class TestUploadAudio:

    # Successfully uploads an audio file and returns job_id
    @pytest.mark.asyncio
    async def test_successful_audio_upload(self, mocker):
        # Arrange
        mock_file = mocker.AsyncMock(spec=UploadFile)
        mock_file.filename = "test_audio.m4a"
        mock_file.read.return_value = b"test audio content"
    
        mock_background_tasks = mocker.MagicMock()
    
        mock_transcribe = mocker.patch("app.services.audio_to_text_service.transcribe_audio")
        mock_transcribe.return_value = "test_job_id"
    
        # Act
        from app.routes.audio import upload_audio
        result = await upload_audio(file=mock_file, background_tasks=mock_background_tasks)
        print("This is the test result: ", result)
    
        # Assert
        assert result == {"message": "Recording received. Processing in background.", "job_id": "test_job_id"}
        mock_transcribe.assert_called_once_with(f"/tmp/test_audio.m4a")
        mock_background_tasks.add_task.assert_called_once()
        mock_file.read.assert_called_once()

# Run the tests using pytest
if __name__ == "__main__":
    pytest.main()